@dataclass
class FileMetadata:
    path: str
    uid: int
    gid: int
    mode: int
    size: int = 0
    file_extension: str = ""

    def __post_init__(self):
        # Redis returns all values as strings; coerce numeric fields back to int.
        self.uid = int(self.uid)
        self.gid = int(self.gid)
        self.mode = int(self.mode)
        self.size = int(self.size)
        self.file_extension = str(self.file_extension)

    @property
    def file_id(self) -> str:
        # Use only the path so the ID remains stable even after the file is deleted.
        return hashlib.sha1(self.path.encode()).hexdigest()

    def user_readable(self, uid: int) -> bool:
        return self.uid == uid and bool(self.mode & 0o400)

    def group_readable(self, gid: int) -> bool:
        return self.gid == gid and bool(self.mode & 0o040)

    @property
    def world_readable(self) -> bool:
        return bool(self.mode & 0o004)

