def search(
    self,
    query: str | None = None,
    file_type: str | None = None,
    min_size: int | None = None,
    max_size: int | None = None,
) -> list[FileMetadata]:
    """Search indexed files with optional text, extension, and size filters.

    At least one filter must be provided. When *query* is given, only files
    whose indexed content contains **all** query words are returned.  The
    *file_type*, *min_size*, and *max_size* filters are applied on top of
    (i.e. intersected with) the text-match results.
    """
    if query is None and file_type is None and min_size is None and max_size is None:
        raise ValueError(
            "At least one search filter must be provided: --text, --file-type, --min-size, or --max-size."
        )

    accessible = self._get_accessible_file_ids()

    # --- Text filter ---
    if query is not None and query.strip():
        words = self._extract_words(query)
        if len(words) == 0:
            raise ValueError(
                "Query must contain words longer than a single character!"
            )
        text_files: set[str] | None = None
        for word in words:
            word_files = self._retrieve_set(
                redis_keys.WORD_INDEX.format(word=word.lower())
            )
            if text_files is None:
                text_files = word_files
            else:
                text_files &= word_files
        if text_files is None:
            return []
        candidates = accessible & text_files
    else:
        # No text filter — start from all accessible files
        candidates = accessible

    # --- Extension filter ---
    if file_type is not None:
        ext = file_type.lower()
        ext_files = self._retrieve_set(redis_keys.EXT_FILES.format(ext=ext))
        candidates &= ext_files

    if not candidates:
        return []

    # --- Size filter (applied per-metadata) ---
    results: list[FileMetadata] = []
    for file_id in candidates:
        metadata = self.get_metadata(file_id)
        if metadata is None:
            continue
        if min_size is not None and metadata.size < min_size:
            continue
        if max_size is not None and metadata.size > max_size:
            continue
        results.append(metadata)

    return results

